import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';

// Assume the function is exported from the module under test
import { matchesSearchQuery } from '../src/utils/search';

describe('matchesSearchQuery', () => {
  // Happy path – typical query matches note content
  it('should handle happy path where query is found in note', () => {
    const note = { title: 'Meeting notes', body: 'Discuss project timeline and milestones' };
    const query = 'project';
    const result = matchesSearchQuery(note, query);
    expect(result).toBe(true);
  });

  // Edge case – empty query should match any note (commonly interpreted as “no filter”)
  it('should handle edge case where query is an empty string', () => {
    const note = { title: 'Shopping List', body: 'Eggs, Milk, Bread' };
    const query = '';
    const result = matchesSearchQuery(note, query);
    expect(result).toBe(true);
  });

  // Null/undefined/zero handling – function should gracefully treat these as empty queries
  it('should handle null/empty inputs without throwing', () => {
    const note = { title: 'Todo', body: 'Finish report' };
    // @ts-expect-error testing runtime behaviour with undefined query
    const resultUndefined = matchesSearchQuery(note, undefined);
    // @ts-expect-error testing runtime behaviour with null query
    const resultNull = matchesSearchQuery(note, null);
    const resultZero = matchesSearchQuery(note, 0 as any);
    const resultEmptyString = matchesSearchQuery(note, '');

    expect(resultUndefined).toBe(true);
    expect(resultNull).toBe(true);
    expect(resultZero).toBe(true);
    expect(resultEmptyString).toBe(true);
  });
});

